module RefModule(
  input clk, reset,
  output reg [SIZE-1:0] out
);parameter SIZE = 4;

  reg [SIZE-1:0] unused_state;

  always @(posedge clk, posedge reset)
    begin
      if (reset) begin
        unused_state <= 0;
        out <= 0;
      end
      else begin
        unused_state <= {unused_state[SIZE-2:0], (unused_state[SIZE-1] ^ unused_state[SIZE-2])}; // Fixed the bit width issue here
        out <= unused_state;
      end
    end

endmodule
